'use client';

import { CheckCircle2, Globe2, TriangleAlert } from 'lucide-react';

import type {
  ProductScrapeProfileImageImportMode,
  ProductScrapeProfile,
  ProductScrapeProfileRunResponse,
  ProductScrapeSourcePriceCurrencyCode,
} from '@/shared/contracts/products/scrape-profiles';
import type { ProductDraft } from '@/shared/contracts/products/drafts';
import { Alert } from '@/shared/ui/alert';
import { Checkbox } from '@/shared/ui/checkbox';
import { Input } from '@/shared/ui/input';
import { Label } from '@/shared/ui/label';
import { SelectSimple } from '@/shared/ui/forms-and-actions.public';
import { cn } from '@/shared/utils/ui-utils';

import { ProductScrapeProfilesResult } from './ProductScrapeProfilesModal.result';
import { ProductScrapeProfilesSourceCurrencyField } from './ProductScrapeProfilesModal.source-currency';

type ProductScrapeProfilesBodyProps = {
  dryRun: boolean;
  error: Error | null;
  isLoading: boolean;
  isDraftTemplatesLoading: boolean;
  imageImportMode: ProductScrapeProfileImageImportMode;
  sourcePriceCurrencyCode: ProductScrapeSourcePriceCurrencyCode;
  limitError: string | null;
  limitInput: string;
  draftTemplates: ProductDraft[];
  profiles: ProductScrapeProfile[];
  result: ProductScrapeProfileRunResponse | null;
  selectedDraftTemplateId: string;
  selectedProfileId: string;
  onDryRunChange: (value: boolean) => void;
  onDraftTemplateSelect: (draftTemplateId: string) => void;
  onImageImportModeChange: (mode: ProductScrapeProfileImageImportMode) => void;
  onSourcePriceCurrencyCodeChange: (code: ProductScrapeSourcePriceCurrencyCode) => void;
  onLimitInputChange: (value: string) => void;
  onProfileSelect: (profileId: string) => void;
};

type ProductScrapeProfilesFormProps = {
  dryRun: boolean;
  isDraftTemplatesLoading: boolean;
  imageImportMode: ProductScrapeProfileImageImportMode;
  sourcePriceCurrencyCode: ProductScrapeSourcePriceCurrencyCode;
  limitError: string | null;
  limitInput: string;
  draftTemplates: ProductDraft[];
  profiles: ProductScrapeProfile[];
  selectedDraftTemplateId: string;
  selectedProfileId: string;
  onDryRunChange: (value: boolean) => void;
  onDraftTemplateSelect: (draftTemplateId: string) => void;
  onImageImportModeChange: (mode: ProductScrapeProfileImageImportMode) => void;
  onSourcePriceCurrencyCodeChange: (code: ProductScrapeSourcePriceCurrencyCode) => void;
  onLimitInputChange: (value: string) => void;
  onProfileSelect: (profileId: string) => void;
};

const NO_DRAFT_TEMPLATE_VALUE = '__no_draft_template__';

type ProductScrapeDraftTemplateOption = {
  value: string;
  label: string;
  description?: string;
};

const profileMeta = (profile: ProductScrapeProfile): string =>
  [
    profile.targetCatalogName,
    profile.maxPages !== null ? `${profile.maxPages} pages` : null,
    profile.defaultLimit !== null ? `${profile.defaultLimit} products` : null,
  ]
    .filter((entry): entry is string => entry !== null)
    .join(' / ');

const hasAssignedScrapeProfile = (draft: ProductDraft): boolean =>
  typeof draft.scrapeProfileId === 'string' && draft.scrapeProfileId.trim().length > 0;

const buildDraftTemplateOptions = (
  draftTemplates: ProductDraft[]
): ProductScrapeDraftTemplateOption[] => [
  { value: NO_DRAFT_TEMPLATE_VALUE, label: 'No template' },
  ...draftTemplates.map((draft) => ({
    value: draft.id,
    label: draft.name,
    description: hasAssignedScrapeProfile(draft) ? 'Profile specific' : 'Any scrape profile',
  })),
];

function ProductScrapeProfileButton(props: {
  profile: ProductScrapeProfile;
  selected: boolean;
  onSelect: (profileId: string) => void;
}): React.JSX.Element {
  const { profile, selected, onSelect } = props;
  return (
    <button
      type='button'
      onClick={() => onSelect(profile.id)}
      className={cn(
        'rounded-md border p-3 text-left transition-colors',
        selected ? 'border-blue-400/60 bg-blue-500/10' : 'border-border/60 bg-card/35 hover:bg-card/55'
      )}
      aria-pressed={selected}
    >
      <div className='flex items-start gap-2'>
        <Globe2 className='mt-0.5 size-4 shrink-0 text-blue-300' aria-hidden='true' />
        <div className='min-w-0 flex-1'>
          <div className='truncate text-sm font-medium text-foreground'>{profile.label}</div>
          <div className='mt-1 text-xs text-muted-foreground'>{profile.siteHost}</div>
          <div className='mt-2 text-[11px] text-muted-foreground'>{profileMeta(profile)}</div>
        </div>
        {selected ? (
          <CheckCircle2 className='size-4 shrink-0 text-emerald-300' aria-hidden='true' />
        ) : null}
      </div>
    </button>
  );
}

function ProductScrapeProfilesLimitField({
  limitError,
  limitInput,
  onLimitInputChange,
}: Pick<
  ProductScrapeProfilesFormProps,
  'limitError' | 'limitInput' | 'onLimitInputChange'
>): React.JSX.Element {
  return (
    <div className='space-y-2'>
      <Label htmlFor='product-scrape-profile-limit'>Limit</Label>
      <Input
        id='product-scrape-profile-limit'
        value={limitInput}
        onChange={(event) => onLimitInputChange(event.target.value)}
        placeholder='All products'
        inputMode='numeric'
        aria-invalid={limitError !== null ? 'true' : undefined}
      />
      {limitError !== null ? (
        <div className='flex items-center gap-1 text-xs text-red-300'>
          <TriangleAlert className='size-3' aria-hidden='true' />
          {limitError}
        </div>
      ) : null}
    </div>
  );
}

function ProductScrapeProfilesDraftTemplateField({
  isDraftTemplatesLoading,
  selectedDraftTemplateId,
  draftTemplateOptions,
  onDraftTemplateSelect,
}: Pick<
  ProductScrapeProfilesFormProps,
  'isDraftTemplatesLoading' | 'selectedDraftTemplateId' | 'onDraftTemplateSelect'
> & {
  draftTemplateOptions: ProductScrapeDraftTemplateOption[];
}): React.JSX.Element {
  return (
    <div className='space-y-2'>
      <Label htmlFor='product-scrape-profile-draft-template'>Draft template</Label>
      <SelectSimple
        id='product-scrape-profile-draft-template'
        size='sm'
        options={draftTemplateOptions}
        value={
          selectedDraftTemplateId.length > 0
            ? selectedDraftTemplateId
            : NO_DRAFT_TEMPLATE_VALUE
        }
        onValueChange={(value): void =>
          onDraftTemplateSelect(value === NO_DRAFT_TEMPLATE_VALUE ? '' : value)
        }
        placeholder={isDraftTemplatesLoading ? 'Loading templates...' : 'No template'}
        ariaLabel='Select scrape draft template'
        title='Select scrape draft template'
        disabled={isDraftTemplatesLoading}
      />
    </div>
  );
}

function ProductScrapeProfilesImageModeField({
  imageImportMode,
  onImageImportModeChange,
}: Pick<
  ProductScrapeProfilesFormProps,
  'imageImportMode' | 'onImageImportModeChange'
>): React.JSX.Element {
  return (
    <div className='space-y-2'>
      <Label htmlFor='product-scrape-profile-image-mode'>Images</Label>
      <SelectSimple
        id='product-scrape-profile-image-mode'
        size='sm'
        options={[
          { value: 'links', label: 'Keep image links' },
          { value: 'files', label: 'Download as files' },
        ]}
        value={imageImportMode}
        onValueChange={(value): void =>
          onImageImportModeChange(value === 'files' ? 'files' : 'links')
        }
        placeholder='Keep image links'
        ariaLabel='Select scrape image import mode'
        title='Select scrape image import mode'
      />
      <p className='text-xs text-muted-foreground'>
        File mode downloads scraped images and attaches them to the product record.
      </p>
    </div>
  );
}

function ProductScrapeProfilesDryRunField({
  dryRun,
  onDryRunChange,
}: Pick<ProductScrapeProfilesFormProps, 'dryRun' | 'onDryRunChange'>): React.JSX.Element {
  return (
    <div className='flex items-center gap-2 self-end pb-2'>
      <Checkbox
        id='product-scrape-profile-dry-run'
        checked={dryRun}
        onCheckedChange={(checked) => onDryRunChange(checked === true)}
      />
      <Label htmlFor='product-scrape-profile-dry-run'>Dry run</Label>
    </div>
  );
}

function ProductScrapeProfilesForm(
  props: ProductScrapeProfilesFormProps
): React.JSX.Element {
  const {
    dryRun,
    isDraftTemplatesLoading,
    imageImportMode,
    sourcePriceCurrencyCode,
    limitError,
    limitInput,
    draftTemplates,
    profiles,
    selectedDraftTemplateId,
    selectedProfileId,
    onDryRunChange,
    onDraftTemplateSelect,
    onImageImportModeChange,
    onSourcePriceCurrencyCodeChange,
    onLimitInputChange,
    onProfileSelect,
  } = props;
  const draftTemplateOptions = buildDraftTemplateOptions(draftTemplates);
  const selectedProfile =
    profiles.find((profile) => profile.id === selectedProfileId) ?? null;
  return (
    <>
      <div className='grid gap-2 md:grid-cols-2'>
        {profiles.map((profile) => (
          <ProductScrapeProfileButton
            key={profile.id}
            profile={profile}
            selected={profile.id === selectedProfileId}
            onSelect={onProfileSelect}
          />
        ))}
      </div>
      <div className='grid gap-4 rounded-md border border-border/60 bg-card/35 p-4 md:grid-cols-[minmax(0,1fr)_minmax(0,1fr)_minmax(0,1fr)_minmax(0,1fr)_auto]'>
        <ProductScrapeProfilesLimitField
          limitError={limitError}
          limitInput={limitInput}
          onLimitInputChange={onLimitInputChange}
        />
        <ProductScrapeProfilesDraftTemplateField
          isDraftTemplatesLoading={isDraftTemplatesLoading}
          selectedDraftTemplateId={selectedDraftTemplateId}
          draftTemplateOptions={draftTemplateOptions}
          onDraftTemplateSelect={onDraftTemplateSelect}
        />
        <ProductScrapeProfilesImageModeField
          imageImportMode={imageImportMode}
          onImageImportModeChange={onImageImportModeChange}
        />
        <ProductScrapeProfilesSourceCurrencyField
          selectedProfile={selectedProfile}
          sourcePriceCurrencyCode={sourcePriceCurrencyCode}
          onSourcePriceCurrencyCodeChange={onSourcePriceCurrencyCodeChange}
        />
        <ProductScrapeProfilesDryRunField dryRun={dryRun} onDryRunChange={onDryRunChange} />
      </div>
    </>
  );
}

export function ProductScrapeProfilesBody(
  props: ProductScrapeProfilesBodyProps
): React.JSX.Element {
  const { error, isLoading, profiles, result, ...formProps } = props;
  let mainContent: React.JSX.Element;
  if (isLoading) {
    mainContent = <div className='text-sm text-muted-foreground'>Loading scrape profiles...</div>;
  } else if (error !== null) {
    mainContent = (
      <Alert variant='error' title='Scrape profiles unavailable' description={error.message} />
    );
  } else if (profiles.length === 0) {
    mainContent = (
      <Alert
        variant='warning'
        title='No scrape profiles'
        description='No product scrape profiles are configured.'
      />
    );
  } else {
    mainContent = <ProductScrapeProfilesForm profiles={profiles} {...formProps} />;
  }

  return (
    <div className='space-y-5'>
      {mainContent}
      {result !== null ? <ProductScrapeProfilesResult result={result} /> : null}
    </div>
  );
}

import type { ProductFormData, ProductDraft } from '@/shared/contracts/products/drafts';
import {
  normalizeProductMarketplaceContentOverrideDrafts,
  type ProductNotes,
  type ProductWithImages,
} from '@/shared/contracts/products/product';
import { PRODUCT_SKU_AUTO_INCREMENT_PLACEHOLDER } from '@/shared/lib/products/constants';
import {
  isGenericProductNamePlaceholder,
  splitStructuredProductName,
} from '@/shared/lib/products/title-terms';

type ProductFormDefaultsInput = {
  product?: ProductWithImages;
  draft?: ProductDraft | null;
  initialSku?: string;
};

const firstDefined = <T,>(
  productValue: T | null | undefined,
  draftValue: T | null | undefined,
  fallback: T
): T => {
  if (productValue !== null && productValue !== undefined) return productValue;
  if (draftValue !== null && draftValue !== undefined) return draftValue;
  return fallback;
};

const firstNonEmptyString = (
  productValue: string | null | undefined,
  draftValue: string | null | undefined
): string => {
  if (typeof productValue === 'string' && productValue.length > 0) return productValue;
  if (typeof draftValue === 'string' && draftValue.length > 0) return draftValue;
  return '';
};

const resolveLocalizedProductName = (
  product: ProductWithImages | undefined,
  languageCode: 'en' | 'pl' | 'de'
): string | null | undefined => {
  const localizedName = product === undefined ? undefined : (product as { name?: unknown }).name;
  if (
    localizedName === null ||
    localizedName === undefined ||
    typeof localizedName !== 'object' ||
    Array.isArray(localizedName)
  ) {
    return undefined;
  }
  const value = (localizedName as Partial<Record<'en' | 'pl' | 'de', unknown>>)[languageCode];
  return typeof value === 'string' && value.length > 0 ? value : undefined;
};

const hasText = (value: string | null): boolean => value !== null && value.length > 0;

const stripDraftPlaceholderBaseName = (value: string | null | undefined): string => {
  if (!value) return '';
  const [baseName = ''] = splitStructuredProductName(value);
  return isGenericProductNamePlaceholder(baseName) ? '' : value;
};

const resolveStringDefault = (
  { product, draft }: ProductFormDefaultsInput,
  key: keyof ProductWithImages & keyof ProductDraft
): string =>
  firstNonEmptyString(
    product?.[key] as string | null | undefined,
    draft?.[key] as string | null | undefined
  );

const resolveNumberDefault = (
  { product, draft }: ProductFormDefaultsInput,
  key: keyof ProductWithImages & keyof ProductDraft
): number =>
  firstDefined(
    product?.[key] as number | null | undefined,
    draft?.[key] as number | null | undefined,
    0
  );

const resolveOptionalNumberDefault = (
  { product, draft }: ProductFormDefaultsInput,
  key: keyof ProductWithImages & keyof ProductDraft
): number | undefined =>
  firstDefined(
    product?.[key] as number | null | undefined,
    draft?.[key] as number | null | undefined,
    undefined
  );

const resolveOptionalDefault = <T,>(
  { product, draft }: ProductFormDefaultsInput,
  key: keyof ProductWithImages & keyof ProductDraft,
  fallback: T
): T =>
  firstDefined(
    product?.[key] as T | null | undefined,
    draft?.[key] as T | null | undefined,
    fallback
  );

const normalizeProductFormNotes = (
  value: ProductNotes | null | undefined
): ProductNotes | undefined => {
  if (value === null || value === undefined) return undefined;
  const text = typeof value.text === 'string' ? value.text : null;
  const color = typeof value.color === 'string' ? value.color : null;
  if (!hasText(text) && !hasText(color)) return undefined;
  return { text, color };
};

const resolveNameDefaults = ({ product, draft }: ProductFormDefaultsInput): Pick<
  ProductFormData,
  'name_en' | 'name_pl' | 'name_de'
> => ({
  name_en: firstNonEmptyString(
    firstNonEmptyString(product?.name_en, resolveLocalizedProductName(product, 'en')),
    stripDraftPlaceholderBaseName(draft?.name_en)
  ),
  name_pl: firstNonEmptyString(
    firstNonEmptyString(product?.name_pl, resolveLocalizedProductName(product, 'pl')),
    stripDraftPlaceholderBaseName(draft?.name_pl)
  ),
  name_de: firstNonEmptyString(
    firstNonEmptyString(product?.name_de, resolveLocalizedProductName(product, 'de')),
    draft?.name_de
  ),
});

const resolveIdentifierDefaults = ({ product, draft, initialSku }: ProductFormDefaultsInput): Pick<
  ProductFormData,
  'asin' | 'ean' | 'gtin' | 'sku'
> => ({
  sku: resolveProductFormDefaultSku({ product, draft, initialSku }),
  ean: firstNonEmptyString(product?.ean, draft?.ean),
  gtin: firstNonEmptyString(product?.gtin, draft?.gtin),
  asin: firstNonEmptyString(product?.asin, draft?.asin),
});

const resolveDescriptionDefaults = (input: ProductFormDefaultsInput): Pick<
  ProductFormData,
  | 'description_de'
  | 'description_en'
  | 'description_pl'
  | 'priceComment'
  | 'supplierLink'
  | 'supplierName'
> => ({
  description_en: resolveStringDefault(input, 'description_en'),
  description_pl: resolveStringDefault(input, 'description_pl'),
  description_de: resolveStringDefault(input, 'description_de'),
  supplierName: resolveStringDefault(input, 'supplierName'),
  supplierLink: resolveStringDefault(input, 'supplierLink'),
  priceComment: resolveStringDefault(input, 'priceComment'),
});

const resolveNumericDefaults = (input: ProductFormDefaultsInput): Pick<
  ProductFormData,
  'length' | 'price' | 'sizeLength' | 'sizeWidth' | 'stock' | 'weight'
> => ({
  price: resolveNumberDefault(input, 'price'),
  stock: resolveNumberDefault(input, 'stock'),
  sizeLength: resolveNumberDefault(input, 'sizeLength'),
  sizeWidth: resolveNumberDefault(input, 'sizeWidth'),
  weight: resolveNumberDefault(input, 'weight'),
  length: resolveNumberDefault(input, 'length'),
});

const resolveOptionalNumericDefaults = (
  input: ProductFormDefaultsInput
): Pick<ProductFormData, 'sourcePrice'> => ({
  sourcePrice: resolveOptionalNumberDefault(input, 'sourcePrice'),
});

const resolveOptionalIdDefaults = (input: ProductFormDefaultsInput): Pick<
  ProductFormData,
  | 'baseProductId'
  | 'defaultPriceGroupId'
  | 'importSource'
  | 'shippingGroupId'
  | 'sourcePriceCurrencyCode'
> => ({
  defaultPriceGroupId: resolveOptionalDefault<string | undefined>(
    input,
    'defaultPriceGroupId',
    undefined
  ),
  baseProductId: resolveOptionalDefault<string | undefined>(input, 'baseProductId', undefined),
  importSource: resolveOptionalDefault<string | undefined>(input, 'importSource', undefined),
  shippingGroupId: resolveOptionalDefault(input, 'shippingGroupId', ''),
  sourcePriceCurrencyCode: resolveOptionalDefault<string | undefined>(
    input,
    'sourcePriceCurrencyCode',
    undefined
  ),
});

const resolveMarketplaceContentDefaults = ({
  product,
  draft,
}: ProductFormDefaultsInput): Pick<ProductFormData, 'marketplaceContentOverrides'> => ({
  marketplaceContentOverrides: normalizeProductMarketplaceContentOverrideDrafts(
    firstDefined(product?.marketplaceContentOverrides, draft?.marketplaceContentOverrides, [])
  ).map((entry) => ({
    integrationIds: entry.integrationIds,
    title: entry.title ?? '',
    description: entry.description ?? '',
  })),
});

export const resolveProductFormDefaultSku = ({
  product,
  draft,
  initialSku,
}: ProductFormDefaultsInput): string => {
  if (typeof product?.sku === 'string' && product.sku.length > 0) return product.sku;
  if (typeof initialSku === 'string' && initialSku.length > 0) return initialSku;
  if (draft !== null && draft !== undefined) return PRODUCT_SKU_AUTO_INCREMENT_PLACEHOLDER;
  return '';
};

export const resolveProductFormDefaultValues = (
  input: ProductFormDefaultsInput
): ProductFormData => ({
  ...resolveNameDefaults(input),
  ...resolveIdentifierDefaults(input),
  ...resolveDescriptionDefaults(input),
  ...resolveNumericDefaults(input),
  ...resolveOptionalNumericDefaults(input),
  ...resolveOptionalIdDefaults(input),
  ...resolveMarketplaceContentDefaults(input),
  notes: normalizeProductFormNotes(input.product?.notes ?? input.draft?.notes ?? undefined),
});

'use client';

'use no memo';

import { useEffect, useMemo, useRef, useState, type Dispatch, type SetStateAction } from 'react';

import { useStudioProjects } from '@/features/ai/public';
import { useProductSettings } from '@/features/products/hooks/useProductSettings';
import {
  useOptionalContextRegistryPageEnvelope,
  useRegisterContextRegistryPageSource,
} from '@/shared/lib/ai-context-registry/page-context';

import { useProductFormCore } from './ProductFormCoreContext';
import { useProductFormImages } from './ProductFormImageContext';
import { useProductFormStudio } from './ProductFormStudioContext';
import {
  useProductStudioActionHandlers,
  type ProductStudioActionHandlers,
} from './ProductStudioContext.actions';
import {
  useProductStudioAuditData,
  useProductStudioVariantsData,
  type ProductStudioAuditData,
  type ProductStudioVariantsData,
} from './ProductStudioContext.data';
import { useProductStudioDerivedState } from './ProductStudioContext.derived';
import {
  useProductImageSlotPreviews,
  useProductStudioInitialImageSelection,
} from './ProductStudioContext.previews';
import {
  useHydrateProductStudioProjectId,
  useProductStudioProjectOptions,
} from './ProductStudioContext.projects';
import {
  useProductStudioActionsValue,
  useProductStudioStateValue,
} from './ProductStudioContext.values';
import type {
  ProductStudioActionsContextValue,
  ProductStudioRunStatus,
  ProductStudioStateContextValue,
} from './ProductStudioContext.types';

type ProductStudioProviderController = {
  actionsValue: ProductStudioActionsContextValue;
  stateValue: ProductStudioStateContextValue;
};

type ProductStudioRunState = {
  activeRunBaselineVariantIds: string[];
  activeRunId: string | null;
  pendingExpectedOutputs: number;
  runStatus: ProductStudioRunStatus | null;
  setActiveRunBaselineVariantIds: Dispatch<SetStateAction<string[]>>;
  setActiveRunId: Dispatch<SetStateAction<string | null>>;
  setPendingExpectedOutputs: Dispatch<SetStateAction<number>>;
  setRunStatus: Dispatch<SetStateAction<ProductStudioRunStatus | null>>;
};

type ProductStudioBaseState = {
  imageLinks: string[];
  imageSlotPreviews: ReturnType<typeof useProductImageSlotPreviews>;
  product: ReturnType<typeof useProductFormCore>['product'];
  productId: string | null;
  productImagesExternalBaseUrl: string;
  refreshImagesFromProduct: ReturnType<typeof useProductFormImages>['refreshImagesFromProduct'];
  selectedImageIndex: number | null;
  setSelectedImageIndex: Dispatch<SetStateAction<number | null>>;
  setStudioProjectId: (id: string | null) => void;
  studioConfigLoading: boolean;
  studioProjectId: string | null;
  studioProjectOptions: ReturnType<typeof useProductStudioProjectOptions>['studioProjectOptions'];
  studioProjectsLoading: boolean;
};

type ProductStudioLoadedState = {
  auditState: ProductStudioAuditData;
  derivedState: ReturnType<typeof useProductStudioDerivedState>;
  variantsState: ProductStudioVariantsData;
};

const useProductStudioRunState = (): ProductStudioRunState => {
  const [activeRunId, setActiveRunId] = useState<string | null>(null);
  const [runStatus, setRunStatus] = useState<ProductStudioRunStatus | null>(null);
  const [activeRunBaselineVariantIds, setActiveRunBaselineVariantIds] = useState<string[]>([]);
  const [pendingExpectedOutputs, setPendingExpectedOutputs] = useState<number>(0);

  return {
    activeRunBaselineVariantIds,
    activeRunId,
    pendingExpectedOutputs,
    runStatus,
    setActiveRunBaselineVariantIds,
    setActiveRunId,
    setPendingExpectedOutputs,
    setRunStatus,
  };
};

const useProductStudioBaseState = (): ProductStudioBaseState => {
  const { studioProjectId, setStudioProjectId, studioConfigLoading, studioConfigSaving } =
    useProductFormStudio();
  const { product } = useProductFormCore();
  const { imageBase64s, imageLinks, imageSlots, refreshImagesFromProduct } = useProductFormImages();
  const studioProjectsQuery = useStudioProjects();
  const { defaultProjectId, getImageExternalBaseUrl } = useProductSettings();
  const productImagesExternalBaseUrl = getImageExternalBaseUrl();
  const productId = product?.id ?? null;
  const [selectedImageIndex, setSelectedImageIndex] = useState<number | null>(null);

  const { studioProjectIds, studioProjectOptions } = useProductStudioProjectOptions(
    studioProjectsQuery.data
  );
  useHydrateProductStudioProjectId({
    configuredDefaultStudioProjectId: defaultProjectId,
    setStudioProjectId,
    studioConfigLoading,
    studioConfigSaving,
    studioProjectId,
    studioProjectIds,
    studioProjectsLoading: studioProjectsQuery.isLoading,
  });

  const imageSlotPreviews = useProductImageSlotPreviews(
    imageSlots,
    imageLinks,
    imageBase64s,
    productImagesExternalBaseUrl
  );
  useProductStudioInitialImageSelection({
    imageSlotPreviews,
    selectedImageIndex,
    setSelectedImageIndex,
  });

  return {
    imageLinks,
    imageSlotPreviews,
    product,
    productId,
    productImagesExternalBaseUrl,
    refreshImagesFromProduct,
    selectedImageIndex,
    setSelectedImageIndex,
    setStudioProjectId,
    studioConfigLoading,
    studioProjectId,
    studioProjectOptions,
    studioProjectsLoading: studioProjectsQuery.isLoading,
  };
};

const useProductStudioLoadedState = (
  base: ProductStudioBaseState,
  runState: ProductStudioRunState
): ProductStudioLoadedState => {
  const variantsState = useProductStudioVariantsData({
    productId: base.productId,
    selectedImageIndex: base.selectedImageIndex,
    studioProjectId: base.studioProjectId,
  });
  const auditState = useProductStudioAuditData({
    productId: base.productId,
    selectedImageIndex: base.selectedImageIndex,
    studioProjectId: base.studioProjectId,
  });

  const derivedState = useProductStudioDerivedState({
    product: base.product,
    studioProjectId: base.studioProjectId,
    selectedImageIndex: base.selectedImageIndex,
    imageSlotPreviews: base.imageSlotPreviews,
    productImagesExternalBaseUrl: base.productImagesExternalBaseUrl,
    selectedVariantSlotId: variantsState.selectedVariantSlotId,
    variantsData: variantsState.variantsData,
    activeRunId: runState.activeRunId,
    runStatus: runState.runStatus,
    activeRunBaselineVariantIds: runState.activeRunBaselineVariantIds,
    pendingExpectedOutputs: runState.pendingExpectedOutputs,
    auditEntries: auditState.auditEntries,
  });

  useRegisterContextRegistryPageSource(
    'product-studio-workspace-state',
    derivedState.registrySource
  );

  return { auditState, derivedState, variantsState };
};

const useProductStudioActionArgs = (
  base: ProductStudioBaseState,
  loaded: ProductStudioLoadedState,
  runState: ProductStudioRunState
): Parameters<typeof useProductStudioActionHandlers>[0] => {
  const contextRegistry = useOptionalContextRegistryPageEnvelope();

  return useMemo(
    () => ({
      contextRegistry,
      imageLinks: base.imageLinks,
      productId: base.productId,
      refreshAudit: loaded.auditState.refreshAudit,
      refreshImagesFromProduct: base.refreshImagesFromProduct,
      refreshVariants: loaded.variantsState.refreshVariants,
      selectedImageIndex: base.selectedImageIndex,
      selectedVariantSlotId: loaded.variantsState.selectedVariantSlotId,
      setActiveRunBaselineVariantIds: runState.setActiveRunBaselineVariantIds,
      setActiveRunId: runState.setActiveRunId,
      setPendingExpectedOutputs: runState.setPendingExpectedOutputs,
      setRunStatus: runState.setRunStatus,
      setStudioActionError: loaded.variantsState.setStudioActionError,
      studioProjectId: base.studioProjectId,
      variantsData: loaded.variantsState.variantsData,
    }),
    [
      base.imageLinks,
      base.productId,
      base.refreshImagesFromProduct,
      base.selectedImageIndex,
      base.studioProjectId,
      contextRegistry,
      loaded.auditState.refreshAudit,
      loaded.variantsState.refreshVariants,
      loaded.variantsState.selectedVariantSlotId,
      loaded.variantsState.setStudioActionError,
      loaded.variantsState.variantsData,
      runState.setActiveRunBaselineVariantIds,
      runState.setActiveRunId,
      runState.setPendingExpectedOutputs,
      runState.setRunStatus,
    ]
  );
};

const useProductStudioContextValues = (
  base: ProductStudioBaseState,
  loaded: ProductStudioLoadedState,
  runState: ProductStudioRunState,
  handlers: ProductStudioActionHandlers
): ProductStudioProviderController => {
  const stateValue = useProductStudioStateValue({
    ...loaded.derivedState,
    accepting: handlers.accepting,
    activeRunId: runState.activeRunId,
    auditEntries: loaded.auditState.auditEntries,
    auditError: loaded.auditState.auditError,
    auditLoading: loaded.auditState.auditLoading,
    deletingVariantId: handlers.deletingVariantId,
    convertingLinkImageIndex: handlers.convertingLinkImageIndex,
    imageSlotPreviews: base.imageSlotPreviews,
    isStudioLoading: base.studioProjectsLoading || base.studioConfigLoading,
    openingInImageStudio: handlers.openingInImageStudio,
    rotatingDirection: handlers.rotatingDirection,
    pendingExpectedOutputs: runState.pendingExpectedOutputs,
    runStatus: runState.runStatus,
    selectedImageIndex: base.selectedImageIndex,
    selectedVariantSlotId: loaded.variantsState.selectedVariantSlotId,
    sending: handlers.sending,
    studioActionError: loaded.variantsState.studioActionError,
    studioProjectId: base.studioProjectId,
    studioProjectOptions: base.studioProjectOptions,
    variantsData: loaded.variantsState.variantsData,
    variantsLoading: loaded.variantsState.variantsLoading,
  });
  const actionsValue = useProductStudioActionsValue({
    ...handlers,
    refreshAudit: loaded.auditState.refreshAudit,
    refreshVariants: loaded.variantsState.refreshVariants,
    setSelectedImageIndex: base.setSelectedImageIndex,
    setSelectedVariantSlotId: loaded.variantsState.setSelectedVariantSlotId,
    setStudioProjectId: base.setStudioProjectId,
  });

  return { actionsValue, stateValue };
};

const VARIANT_POLL_INTERVAL_MS = 4000;
const RUN_TIMEOUT_MS = 5 * 60 * 1000;

const useProductStudioRunEffects = (
  loaded: ProductStudioLoadedState,
  runState: ProductStudioRunState
): void => {
  const { pendingVariantPlaceholderCount } = loaded.derivedState;
  const { refreshVariants, selectedVariantSlotId, setSelectedVariantSlotId } = loaded.variantsState;
  const { refreshAudit } = loaded.auditState;
  const {
    activeRunId,
    activeRunBaselineVariantIds,
    pendingExpectedOutputs,
    runStatus,
    setActiveRunBaselineVariantIds,
    setActiveRunId,
    setPendingExpectedOutputs,
    setRunStatus,
  } = runState;

  // Stable refs so interval callbacks read current values without effect churn
  const baselineIdsRef = useRef(activeRunBaselineVariantIds);
  baselineIdsRef.current = activeRunBaselineVariantIds;
  const selectedVariantSlotIdRef = useRef(selectedVariantSlotId);
  selectedVariantSlotIdRef.current = selectedVariantSlotId;
  const prevPlaceholderCountRef = useRef(pendingVariantPlaceholderCount);

  // Auto-poll variants while generation is in progress; auto-select first new variant
  useEffect(() => {
    if (pendingVariantPlaceholderCount === 0) return;
    const id = setInterval(() => {
      refreshVariants()
        .then((result) => {
          if (result === null) return;
          const baselineSet = new Set(baselineIdsRef.current);
          const currentIsBaseline =
            selectedVariantSlotIdRef.current === null ||
            baselineSet.has(selectedVariantSlotIdRef.current);
          if (!currentIsBaseline) return;
          const firstNew = result.variants.find((slot) => !baselineSet.has(slot.id));
          if (firstNew !== undefined) setSelectedVariantSlotId(firstNew.id);
        })
        .catch(() => undefined);
    }, VARIANT_POLL_INTERVAL_MS);
    return () => clearInterval(id);
  }, [pendingVariantPlaceholderCount, refreshVariants, setSelectedVariantSlotId]);

  // Advance status from 'queued' to 'running' once the first output variant arrives
  useEffect(() => {
    if (runStatus !== 'queued' || pendingExpectedOutputs === 0) return;
    const variantsArrived = pendingExpectedOutputs - pendingVariantPlaceholderCount;
    if (variantsArrived > 0) setRunStatus('running');
  }, [pendingExpectedOutputs, pendingVariantPlaceholderCount, runStatus, setRunStatus]);

  // Clear run state and refresh audit once all expected variants have arrived
  useEffect(() => {
    const prev = prevPlaceholderCountRef.current;
    prevPlaceholderCountRef.current = pendingVariantPlaceholderCount;
    if (prev > 0 && pendingVariantPlaceholderCount === 0 && activeRunId !== null) {
      setRunStatus(null);
      setActiveRunId(null);
      setPendingExpectedOutputs(0);
      setActiveRunBaselineVariantIds([]);
      void refreshAudit();
    }
  }, [
    activeRunId,
    pendingVariantPlaceholderCount,
    refreshAudit,
    setActiveRunBaselineVariantIds,
    setActiveRunId,
    setPendingExpectedOutputs,
    setRunStatus,
  ]);

  // Restore run state from Redis-persisted active run on modal reopen.
  // Skip restoration if all expected variants have already arrived to avoid
  // a phantom "running" badge when the user reopens after a completed run.
  useEffect(() => {
    const activeRun = loaded.variantsState.variantsData?.activeRun ?? null;
    if (activeRun === null || activeRunId !== null) return;
    const currentVariants = loaded.variantsState.variantsData?.variants ?? [];
    const baselineSet = new Set(activeRun.baselineVariantIds);
    const alreadyArrived = currentVariants.filter((v) => !baselineSet.has(v.id)).length;
    if (alreadyArrived >= activeRun.pendingExpectedOutputs) return;
    setActiveRunId(activeRun.runId);
    setRunStatus(activeRun.runStatus);
    setPendingExpectedOutputs(activeRun.pendingExpectedOutputs);
    setActiveRunBaselineVariantIds(activeRun.baselineVariantIds);
  }, [
    activeRunId,
    loaded.variantsState.variantsData,
    setActiveRunBaselineVariantIds,
    setActiveRunId,
    setPendingExpectedOutputs,
    setRunStatus,
  ]);

  // Safety timeout: force-clear run state if the server run never delivers all expected outputs
  useEffect(() => {
    if (pendingVariantPlaceholderCount === 0) return;
    const id = setTimeout(() => {
      setRunStatus(null);
      setActiveRunId(null);
      setPendingExpectedOutputs(0);
      setActiveRunBaselineVariantIds([]);
    }, RUN_TIMEOUT_MS);
    return () => clearTimeout(id);
  }, [
    pendingVariantPlaceholderCount,
    setActiveRunBaselineVariantIds,
    setActiveRunId,
    setPendingExpectedOutputs,
    setRunStatus,
  ]);
};

export const useProductStudioProviderController = (): ProductStudioProviderController => {
  const base = useProductStudioBaseState();
  const runState = useProductStudioRunState();
  const loaded = useProductStudioLoadedState(base, runState);
  const actionArgs = useProductStudioActionArgs(base, loaded, runState);
  const handlers = useProductStudioActionHandlers(actionArgs);
  useProductStudioRunEffects(loaded, runState);
  return useProductStudioContextValues(base, loaded, runState, handlers);
};
